class Solution:
    def findReplaceString(self, s, indices, sources, targets):
        ops = sorted(zip(indices, sources, targets))
        out = []
        i = 0
        j = 0
        n = len(s)
        while i < n:
            if j < len(ops) and ops[j][0] == i:
                idx, src, tgt = ops[j]
                if s[i:i + len(src)] == src:
                    out.append(tgt)
                    i += len(src)
                    j += 1
                    continue
                else:
                    j += 1
            out.append(s[i])
            i += 1
        return ''.join(out)

