class Solution:
    def findReplaceString(self, s, indices, sources, targets):
        ops = sorted(zip(indices, sources, targets), key=lambda o: o[0])
        res = []
        cur = 0
        for idx, src, tgt in ops:
            res.append(s[cur:idx])
            if s[idx:idx + len(src)] == src:
                res.append(tgt)
                cur = idx + len(src)
            else:
                res.append(s[idx:idx + len(src)])
                cur = idx + len(src)
        res.append(s[cur:])
        return ''.join(res)

