var findReplaceString = function(s, indices, sources, targets) {
    const ops = indices.map((idx, i) => [idx, sources[i], targets[i]]);
    ops.sort((a, b) => a[0] - b[0]);
    const res = [];
    let cur = 0;
    for (const [idx, src, tgt] of ops) {
        res.push(s.slice(cur, idx));
        if (s.slice(idx, idx + src.length) === src) {
            res.push(tgt);
        } else {
            res.push(s.slice(idx, idx + src.length));
        }
        cur = idx + src.length;
    }
    res.push(s.slice(cur));
    return res.join('');
};
